// mm/src/api/downloadDocuments.js
import axios from 'axios';
import { withAuthRetry } from './refresh';
import { getAccessToken } from '../utils/auth';

const API_BASE =
  process.env.REACT_APP_API_BASE_URL || 'https://manuscriptmagic.fowkes.xyz/services';

/**
 * Extract filename from Content-Disposition header if present.
 * Supports:
 *  - filename="file.docx"
 *  - filename=file.docx
 *  - filename*=UTF-8''file%20name.docx
 */
function getFilenameFromContentDisposition(cd) {
  const v = String(cd || '');
  if (!v) return '';

  // filename*=UTF-8''name%20here.docx
  const mStar = v.match(/filename\*\s*=\s*([^;]+)/i);
  if (mStar) {
    const raw = mStar[1].trim().replace(/^UTF-8''/i, '').replace(/^"|"$/g, '');
    try {
      return decodeURIComponent(raw);
    } catch {
      return raw;
    }
  }

  // filename="name.docx"
  const m = v.match(/filename\s*=\s*([^;]+)/i);
  if (m) return m[1].trim().replace(/^"|"$/g, '');

  return '';
}

/**
 * Downloads from:
 *   GET /downloadDocument.php?id=<documentId>
 * with Authorization: Bearer <accessToken>
 *
 * Returns the axios response (data is a Blob).
 */
export async function downloadDocument(documentId) {
  if (!documentId) throw new Error('documentId is required');

  // DEV MOCK
  if (!process.env.REACT_APP_API_BASE_URL) {
    const blob = new Blob([`Mock file for ${documentId}`], { type: 'text/plain' });
    return { data: blob, headers: { 'content-type': 'text/plain' } };
  }

  const url = `${API_BASE}/downloadDocument.php`;

  return withAuthRetry(async () => {
    const accessToken = await getAccessToken();
    if (!accessToken) throw new Error('Missing access token');

    console.log('📥 downloadDocument request:', {
      url,
      documentId,
      tokenPrefix: String(accessToken).slice(0, 12) + '...',
    });

    // Match your “working” fetch() behavior: GET with id query param
    return axios.get(url, {
      params: { id: documentId },
      responseType: 'blob',
      headers: {
        Authorization: `Bearer ${accessToken}`,
        Accept: '*/*',
      },
      // Don’t throw automatically; we want to parse backend error bodies when possible
      validateStatus: () => true,
    });
  });
}

/**
 * Downloads + saves to disk.
 * Similar behavior to your working fetch() example.
 */
export async function downloadAndSaveDocuments(documentId, fallbackFilename = 'downloaded_file') {
  const resp = await downloadDocument(documentId);

  // If non-2xx, try to parse JSON error (or text)
  if (!resp || resp.status < 200 || resp.status >= 300) {
    // Axios gave us a Blob because responseType is blob, even for errors.
    const errBlob = resp?.data;

    let message = `Download failed (HTTP ${resp?.status || 'unknown'})`;

    try {
      if (errBlob instanceof Blob) {
        const text = await errBlob.text();
        // try JSON
        try {
          const json = JSON.parse(text);
          message = json?.error || json?.message || message;
        } catch {
          // plain text error
          if (text.trim()) message = text.trim();
        }
      }
    } catch {
      // ignore parse errors
    }

    throw new Error(message);
  }

  const blob = resp.data;
  if (!(blob instanceof Blob)) {
    throw new Error('Download failed: backend did not return a Blob.');
  }

  const contentType = resp.headers?.['content-type'] || resp.headers?.['Content-Type'] || blob.type || '';

  // Check if the response is actually an error (e.g., HTML error page or JSON error)
  if (contentType.includes('text/html') || contentType.includes('application/json')) {
    try {
      const text = await blob.text();
      let message = 'Download failed: received error response from server.';
      try {
        const json = JSON.parse(text);
        message = json?.error || json?.message || message;
      } catch {
        if (text.trim()) message = text.trim();
      }
      throw new Error(message);
    } catch (parseError) {
      throw new Error('Download failed: invalid response format.');
    }
  }

  if (blob.size === 0) {
    throw new Error('Download failed: received empty file.');
  }

  // Filename from headers (preferred)
  const cd = resp.headers?.['content-disposition'] || resp.headers?.['Content-Disposition'] || '';
  const headerFilename = getFilenameFromContentDisposition(cd);

  const filename = headerFilename || fallbackFilename || 'downloaded_file';

  console.log('✅ downloadDocument success:', {
    documentId,
    status: resp.status,
    filename,
    contentType: resp.headers?.['content-type'] || blob.type || '',
    bytes: blob.size,
  });

  // Save file
  const url = window.URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  a.remove();
  window.URL.revokeObjectURL(url);

  return { success: true };
}
